20	#ifndef SATGEN_H
21	#define SATGEN_H
22	
23	#include "kernel/rtlil.h"
24	#include "kernel/sigtools.h"
25	#include "kernel/celltypes.h"
26	#include "kernel/macc.h"
27	
28	#include "libs/ezsat/ezminisat.h"
29	
30	YOSYS_NAMESPACE_BEGIN
31	
32	// defined in kernel/register.cc
33	extern struct SatSolver *yosys_satsolver_list;
34	extern struct SatSolver *yosys_satsolver;
35	
36	struct SatSolver
37	{
38		string name;
39		SatSolver *next;
40		virtual ezSAT *create() = 0;
41	
42		SatSolver(string name) : name(name) {
43			next = yosys_satsolver_list;
44			yosys_satsolver_list = this;
45		}
46	
47		virtual ~SatSolver() {
48			auto p = &yosys_satsolver_list;
49			while (*p) {
50				if (*p == this)
51					*p = next;
52				else
53					p = &(*p)->next;
54			}
55			if (yosys_satsolver == this)
56				yosys_satsolver = yosys_satsolver_list;
57		}
58	};
59	
60	struct ezSatPtr : public std::unique_ptr<ezSAT> {
61		ezSatPtr() : unique_ptr<ezSAT>(yosys_satsolver->create()) { }
62		explicit ezSatPtr(SatSolver *solver) : unique_ptr<ezSAT>((solver ? solver : yosys_satsolver)->create()) { }
63	};
64	
65	struct SatGen
66	{
67		ezSAT *ez;
68		const SigMap *sigmap;
69		std::string prefix;
70		SigPool initial_state;
71		std::map<std::string, RTLIL::SigSpec> asserts_a, asserts_en;
72		std::map<std::string, RTLIL::SigSpec> assumes_a, assumes_en;
73		std::map<std::string, std::map<RTLIL::SigBit, int>> imported_signals;
74		std::map<std::pair<std::string, int>, bool> initstates;
75		bool ignore_div_by_zero;
76		bool model_undef;
77		bool def_formal = false;
78	
79		SatGen(ezSAT *ez, const SigMap *sigmap, std::string prefix = std::string()) :
80				ez(ez), sigmap(sigmap), prefix(prefix), ignore_div_by_zero(false), model_undef(false)
81		{
82		}
83	
84		void setContext(const SigMap *sigmap, std::string prefix = std::string())
85		{
86			this->sigmap = sigmap;
87			this->prefix = prefix;
88		}
89	
90		std::vector<int> importSigSpecWorker(RTLIL::SigSpec sig, std::string &pf, bool undef_mode, bool dup_undef)
91		{
92			log_assert(!undef_mode || model_undef);
93			sigmap->apply(sig);
94	
95			std::vector<int> vec;
96			vec.reserve(GetSize(sig));
97	
98			for (auto &bit : sig)
99				if (bit.wire == NULL) {
100					if (model_undef && dup_undef && bit == RTLIL::State::Sx)
101						vec.push_back(ez->frozen_literal());
102					else
103						vec.push_back(bit == (undef_mode ? RTLIL::State::Sx : RTLIL::State::S1) ? ez->CONST_TRUE : ez->CONST_FALSE);
104				} else {
105					std::string wire_name = bit.wire->name.unescape();
106					std::string name = pf +
107						(bit.wire->width == 1 ? wire_name : stringf("%s [%d]", wire_name, bit.offset));
108					vec.push_back(ez->frozen_literal(name));
109					imported_signals[pf][bit] = vec.back();
110				}
111			return vec;
112		}
113	
114		std::vector<int> importSigSpec(RTLIL::SigSpec sig, int timestep = -1)
115		{
116			log_assert(timestep != 0);
117			std::string pf = prefix + (timestep == -1 ? "" : stringf("@%d:", timestep));
118			return importSigSpecWorker(sig, pf, false, false);
119		}
120	
121		std::vector<int> importDefSigSpec(RTLIL::SigSpec sig, int timestep = -1)
122		{
123			log_assert(timestep != 0);
124			std::string pf = prefix + (timestep == -1 ? "" : stringf("@%d:", timestep));
125			return importSigSpecWorker(sig, pf, false, true);
126		}
127	
128		std::vector<int> importUndefSigSpec(RTLIL::SigSpec sig, int timestep = -1)
129		{
130			log_assert(timestep != 0);
131			std::string pf = "undef:" + prefix + (timestep == -1 ? "" : stringf("@%d:", timestep));
132			return importSigSpecWorker(sig, pf, true, false);
133		}
134	
135		int importSigBit(RTLIL::SigBit bit, int timestep = -1)
136		{
137			log_assert(timestep != 0);
138			std::string pf = prefix + (timestep == -1 ? "" : stringf("@%d:", timestep));
139			return importSigSpecWorker(bit, pf, false, false).front();
140		}
141	
142		int importDefSigBit(RTLIL::SigBit bit, int timestep = -1)
143		{
144			log_assert(timestep != 0);
145			std::string pf = prefix + (timestep == -1 ? "" : stringf("@%d:", timestep));
146			return importSigSpecWorker(bit, pf, false, true).front();
147		}
148	
149		int importUndefSigBit(RTLIL::SigBit bit, int timestep = -1)
150		{
151			log_assert(timestep != 0);
152			std::string pf = "undef:" + prefix + (timestep == -1 ? "" : stringf("@%d:", timestep));
153			return importSigSpecWorker(bit, pf, true, false).front();
154		}
155	
156		bool importedSigBit(RTLIL::SigBit bit, int timestep = -1)
157		{
158			log_assert(timestep != 0);
159			std::string pf = prefix + (timestep == -1 ? "" : stringf("@%d:", timestep));
160			return imported_signals[pf].count(bit) != 0;
161		}
162	
163		void getAsserts(RTLIL::SigSpec &sig_a, RTLIL::SigSpec &sig_en, int timestep = -1)
164		{
165			std::string pf = prefix + (timestep == -1 ? "" : stringf("@%d:", timestep));
166			sig_a = asserts_a[pf];
167			sig_en = asserts_en[pf];
168		}
169	
170		void getAssumes(RTLIL::SigSpec &sig_a, RTLIL::SigSpec &sig_en, int timestep = -1)
171		{
172			std::string pf = prefix + (timestep == -1 ? "" : stringf("@%d:", timestep));
173			sig_a = assumes_a[pf];
174			sig_en = assumes_en[pf];
175		}
176	
177		int importAsserts(int timestep = -1)
178		{
179			std::vector<int> check_bits, enable_bits;
180			std::string pf = prefix + (timestep == -1 ? "" : stringf("@%d:", timestep));
181			if (model_undef) {
182				check_bits = ez->vec_and(ez->vec_not(importUndefSigSpec(asserts_a[pf], timestep)), importDefSigSpec(asserts_a[pf], timestep));
183				enable_bits = ez->vec_and(ez->vec_not(importUndefSigSpec(asserts_en[pf], timestep)), importDefSigSpec(asserts_en[pf], timestep));
184			} else {
185				check_bits = importDefSigSpec(asserts_a[pf], timestep);
186				enable_bits = importDefSigSpec(asserts_en[pf], timestep);
187			}
188			return ez->vec_reduce_and(ez->vec_or(check_bits, ez->vec_not(enable_bits)));
189		}
190	
191		int importAssumes(int timestep = -1)
192		{
193			std::vector<int> check_bits, enable_bits;
194			std::string pf = prefix + (timestep == -1 ? "" : stringf("@%d:", timestep));
195			if (model_undef) {
196				check_bits = ez->vec_and(ez->vec_not(importUndefSigSpec(assumes_a[pf], timestep)), importDefSigSpec(assumes_a[pf], timestep));
197				enable_bits = ez->vec_and(ez->vec_not(importUndefSigSpec(assumes_en[pf], timestep)), importDefSigSpec(assumes_en[pf], timestep));
198			} else {
199				check_bits = importDefSigSpec(assumes_a[pf], timestep);
200				enable_bits = importDefSigSpec(assumes_en[pf], timestep);
201			}
202			return ez->vec_reduce_and(ez->vec_or(check_bits, ez->vec_not(enable_bits)));
203		}
204	
205		int signals_eq(RTLIL::SigSpec lhs, RTLIL::SigSpec rhs, int timestep_lhs = -1, int timestep_rhs = -1)
206		{
207			if (timestep_rhs < 0)
208				timestep_rhs = timestep_lhs;
209	
210			log_assert(lhs.size() == rhs.size());
211	
212			std::vector<int> vec_lhs = importSigSpec(lhs, timestep_lhs);
213			std::vector<int> vec_rhs = importSigSpec(rhs, timestep_rhs);
214	
215			if (!model_undef)
216				return ez->vec_eq(vec_lhs, vec_rhs);
217	
218			std::vector<int> undef_lhs = importUndefSigSpec(lhs, timestep_lhs);
219			std::vector<int> undef_rhs = importUndefSigSpec(rhs, timestep_rhs);
220	
221			std::vector<int> eq_bits;
222			for (int i = 0; i < lhs.size(); i++)
223				eq_bits.push_back(ez->AND(ez->IFF(undef_lhs.at(i), undef_rhs.at(i)),
224						ez->IFF(ez->OR(vec_lhs.at(i), undef_lhs.at(i)), ez->OR(vec_rhs.at(i), undef_rhs.at(i)))));
225			return ez->expression(ezSAT::OpAnd, eq_bits);
226		}
227	
228		void extendSignalWidth(std::vector<int> &vec_a, std::vector<int> &vec_b, RTLIL::Cell *cell, size_t y_width = 0, bool forced_signed = false)
229		{
230			bool is_signed = forced_signed;
231			if (!forced_signed && cell->parameters.count(ID::A_SIGNED) > 0 && cell->parameters.count(ID::B_SIGNED) > 0)
232				is_signed = cell->parameters[ID::A_SIGNED].as_bool() && cell->parameters[ID::B_SIGNED].as_bool();
233			while (vec_a.size() < vec_b.size() || vec_a.size() < y_width)
234				vec_a.push_back(is_signed && vec_a.size() > 0 ? vec_a.back() : ez->CONST_FALSE);
235			while (vec_b.size() < vec_a.size() || vec_b.size() < y_width)
236				vec_b.push_back(is_signed && vec_b.size() > 0 ? vec_b.back() : ez->CONST_FALSE);
237		}
238	
239		void extendSignalWidth(std::vector<int> &vec_a, std::vector<int> &vec_b, std::vector<int> &vec_y, RTLIL::Cell *cell, bool forced_signed = false)
240		{
241			extendSignalWidth(vec_a, vec_b, cell, vec_y.size(), forced_signed);
242			while (vec_y.size() < vec_a.size())
243				vec_y.push_back(ez->literal());
244		}
245	
246		void extendSignalWidthUnary(std::vector<int> &vec_a, std::vector<int> &vec_y, RTLIL::Cell *cell, bool forced_signed = false)
247		{
248			bool is_signed = forced_signed || (cell->parameters.count(ID::A_SIGNED) > 0 && cell->parameters[ID::A_SIGNED].as_bool());
249			while (vec_a.size() < vec_y.size())
250				vec_a.push_back(is_signed && vec_a.size() > 0 ? vec_a.back() : ez->CONST_FALSE);
251			while (vec_y.size() < vec_a.size())
252				vec_y.push_back(ez->literal());
253		}
254	
255		void undefGating(std::vector<int> &vec_y, std::vector<int> &vec_yy, std::vector<int> &vec_undef)
256		{
257			log_assert(model_undef);
258			log_assert(vec_y.size() == vec_yy.size());
259			if (vec_y.size() > vec_undef.size()) {
260				std::vector<int> trunc_y(vec_y.begin(), vec_y.begin() + vec_undef.size());
261				std::vector<int> trunc_yy(vec_yy.begin(), vec_yy.begin() + vec_undef.size());
262				ez->assume(ez->expression(ezSAT::OpAnd, ez->vec_or(vec_undef, ez->vec_iff(trunc_y, trunc_yy))));
263			} else {
264				log_assert(vec_y.size() == vec_undef.size());
265				ez->assume(ez->expression(ezSAT::OpAnd, ez->vec_or(vec_undef, ez->vec_iff(vec_y, vec_yy))));
266			}
267		}
268	
269		std::pair<std::vector<int>, std::vector<int>> mux(int s, int undef_s, const std::vector<int> &a, const std::vector<int> &undef_a, const std::vector<int> &b, const std::vector<int> &undef_b) {
270			std::vector<int> res;
271			std::vector<int> undef_res;
272			res = ez->vec_ite(s, b, a);
273			if (model_undef) {
274				std::vector<int> unequal_ab = ez->vec_not(ez->vec_iff(a, b));
275				std::vector<int> undef_ab = ez->vec_or(unequal_ab, ez->vec_or(undef_a, undef_b));
276				undef_res = ez->vec_ite(undef_s, undef_ab, ez->vec_ite(s, undef_b, undef_a));
277			}
278			return std::make_pair(res, undef_res);
279		}
280	
281		void undefGating(int y, int yy, int undef)
282		{
283			ez->assume(ez->OR(undef, ez->IFF(y, yy)));
284		}
285	
286		void setInitState(int timestep)
287		{
288			auto key = make_pair(prefix, timestep);
289			log_assert(initstates.count(key) == 0 || initstates.at(key) == true);
290			initstates[key] = true;
291		}
292	
293		bool importCell(RTLIL::Cell *cell, int timestep = -1);
294	};
295	
296	void report_missing_model(bool warn_only, RTLIL::Cell* cell);
297	
298	YOSYS_NAMESPACE_END
299	
300	#endif
