26	bool SatGen::importCell(RTLIL::Cell *cell, int timestep)
27	{
28		bool arith_undef_handled = false;
29		bool is_arith_compare = cell->type.in(ID($lt), ID($le), ID($ge), ID($gt));
30	
31		if (model_undef && (cell->type.in(ID($add), ID($sub), ID($mul), ID($div), ID($mod), ID($divfloor), ID($modfloor)) || is_arith_compare))
32		{
33			std::vector<int> undef_a = importUndefSigSpec(cell->getPort(ID::A), timestep);
34			std::vector<int> undef_b = importUndefSigSpec(cell->getPort(ID::B), timestep);
35			std::vector<int> undef_y = importUndefSigSpec(cell->getPort(ID::Y), timestep);
36			if (is_arith_compare)
37				extendSignalWidth(undef_a, undef_b, cell, true);
38			else
39				extendSignalWidth(undef_a, undef_b, undef_y, cell, true);
40	
41			int undef_any_a = ez->expression(ezSAT::OpOr, undef_a);
42			int undef_any_b = ez->expression(ezSAT::OpOr, undef_b);
43			int undef_y_bit = ez->OR(undef_any_a, undef_any_b);
44	
45			if (cell->type.in(ID($div), ID($mod), ID($divfloor), ID($modfloor))) {
46				std::vector<int> b = importSigSpec(cell->getPort(ID::B), timestep);
47				undef_y_bit = ez->OR(undef_y_bit, ez->NOT(ez->expression(ezSAT::OpOr, b)));
48			}
